@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // During SSR this persists the data into the HTML payload.
        // During interactive activation this restores it, avoiding a second fetch.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                "notifications", out var restored))
        {
            // Interactive activation — reuse the SSR data.
            _notifications = restored!;
        }
        else
        {
            // SSR — load from the service once.
            _notifications = NotificationSvc.GetAll();
        }

        _lastSeenId = _notifications.Count > 0
            ? _notifications.Max(n => n.Id)
            : 0;
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson("notifications", _notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during static SSR, so this
            // guarantees the polling loop only starts once the circuit is live.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct)
                       .ConfigureAwait(false);

            // Simulate some external system producing notifications.
            NotificationSvc.SimulateActivity();

            var newer = NotificationSvc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

