namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();
    private readonly Random _random = new();

    private static readonly string[] Templates =
    [
        "Your build completed successfully.",
        "New comment on PR #42.",
        "Deployment to staging finished.",
        "Disk usage above 80% on prod-web-1.",
        "User 'admin' logged in from a new device.",
        "Backup completed for database 'orders'.",
        "Certificate for api.example.com expires in 7 days.",
        "New release v2.4.0 is available.",
    ];

    public NotificationService()
    {
        // Seed a few initial notifications so SSR has something to render.
        for (var i = 0; i < 3; i++)
        {
            _notifications.Add(new Notification(
                _nextId++,
                Templates[_random.Next(Templates.Length)],
                DateTime.UtcNow.AddMinutes(-_random.Next(1, 60))));
        }
    }

    /// <summary>Returns all notifications currently stored.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns notifications added after the given id.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates external activity by occasionally adding a notification.
    /// Called by the polling loop on the interactive page.
    /// </summary>
    public void SimulateActivity()
    {
        lock (_lock)
        {
            // ~40 % chance a new notification appears each tick.
            if (_random.Next(100) < 40)
            {
                _notifications.Add(new Notification(
                    _nextId++,
                    Templates[_random.Next(Templates.Length)],
                    DateTime.UtcNow));
            }
        }
    }
}

